import { test, expect } from '@playwright/test';

// Helper for login using storageState
async function login(page) {
  await page.context().addCookies([]);
  await page.goto('https://www.amazon.com', { waitUntil: 'domcontentloaded' });
  await page.context().storageState({ path: 'user.json' });
  console.log('[step] ✅ Login using storageState');
}

test('Amazon search and filter - laptop under $500', async ({ page }) => {
  // Step 1: Navigate to Amazon homepage
  await login(page);
  await page.goto('https://www.amazon.com');
  await page.waitForLoadState('networkidle');
  console.log('[step] ✅ Navigated to Amazon homepage and waited for networkidle');

  // Step 3: Locate the search input using only locator chains and .first() for ambiguity
  const searchInput = page.locator('input#twotabsearchtextbox').first(); // [AI-HEAL] Removed mixed selector types and used .first() for ambiguity
  await expect(searchInput).toBeVisible({ timeout: 10000 });
  console.log('[step] ✅ Located search input with locator chain and .first()');

  // Step 4: Enter search term: “laptop”
  await searchInput.fill('laptop');
  console.log('[step] ✅ Entered search term: laptop');

  // Step 5: Submit the search
  await searchInput.press('Enter');
  await page.waitForLoadState('networkidle');
  console.log('[step] ✅ Submitted search and waited for results page networkidle');

  // Step 7: Locate and click the Filter (e.g., “Price: Under $500”) using only locator chains and .first()
  const priceFilter = page.locator('span:has-text("Under $500")').first(); // [AI-HEAL] Removed mixed selector types and used .first() for ambiguity
  await expect(priceFilter).toBeVisible({ timeout: 15000 });
  await priceFilter.scrollIntoViewIfNeeded();
  try {
    await priceFilter.click();
  } catch (e) {
    // [AI-HEAL] Added fallback click strategy for dynamic element
    await priceFilter.evaluate((el: HTMLElement) => el.click());
  }
  await page.waitForLoadState('networkidle');
  console.log('[step] ✅ Clicked Price: Under $500 filter and waited for filtered results');

  // Step 9: Scroll into view if needed and verify product cards are visible using locator chains and .first()
  const productCard = page.locator('.s-result-item').first(); // [AI-HEAL] Removed mixed selector types and used .first() for ambiguity
  await productCard.scrollIntoViewIfNeeded();
  await expect(productCard).toBeVisible({ timeout: 15000 });
  console.log('[step] ✅ Scrolled product card into view and verified visibility');

  // Step 10: Confirm at least one product result is displayed using locator chains
  const productCards = page.locator('.s-result-item'); // [AI-HEAL] Removed mixed selector types for product cards
  const count = await productCards.count();
  expect(count).toBeGreaterThan(0);
  console.log(`[step] ✅ Confirmed at least one product result is displayed (${count} found)`);
});
